code.perFrame:
zoom = 0.99951;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
beatb=((bass) > (bass_att));;
beatbhard=if(beatb,bass-bass_att*.9,beatbhard);;
beatm=((mid) > (mid_att));;
beatmhard=if(beatm,mid-mid_att*.9,beatmhard);;
beatt=((treb) > (treb_att));;
beatthard=if(beatt,treb-treb_att*.9,beatthard);;
vol=bass+mid+treb;;
vol_att=bass_att+mid_att+treb_att;;
q1=beatb;;
q2=beatbhard;;
q3=beatm;;
q4=beatmhard;;
q5=beatt;;
q6=beatthard;;
q8=10*bass_att*q4;;
decay=.98;;
wrap=0;
